import { NonVirtualizedTooltipBody } from './NonVirtualizedTooltipBody.js';
import type { TooltipBodyProps } from '../types/tooltip.js';
import { VirtualizedTooltipBody } from './VirtualizedTooltipBody/VirtualizedTooltipBody.js';

const DEFAULT_VIRTUALIZATION = true;

export const TooltipBody = (props: TooltipBodyProps) => {
  const {
    children,
    virtualization = DEFAULT_VIRTUALIZATION,
    itemHeight,
    onScrollContent,
    ...rest
  } = props;

  return virtualization ? (
    <VirtualizedTooltipBody
      estimatedItemSize={itemHeight}
      onScrollContent={onScrollContent}
      {...rest}
    >
      {children}
    </VirtualizedTooltipBody>
  ) : (
    <NonVirtualizedTooltipBody {...rest}>{children}</NonVirtualizedTooltipBody>
  );
};

TooltipBody['displayName'] = 'TooltipBody';
